#!/usr/bin/env python3
"""Random differential fuzzer comparing reference and our binary."""
import subprocess
import random
import string
import sys

REF = "/workspace/executable"
MINE = "/work/work/executable"

STYLES = ["none", "ascii", "ascii2", "sharp", "rounded", "reinforced", "markdown", "grid"]
ALIGNS = ["left", "center", "right"]


def random_args():
    args = []
    if random.random() < 0.3:
        args.append("-H")
    if random.random() < 0.3:
        args.append("-n")
    if random.random() < 0.2:
        args.append("-t")
        # don't combine with -d if -t
    elif random.random() < 0.3:
        args += ["-d", random.choice([",", ";", "|", "X", "@"])]
    if random.random() < 0.5:
        args += ["-s", random.choice(STYLES)]
    if random.random() < 0.4:
        args += ["-p", str(random.randint(0, 5))]
    if random.random() < 0.4:
        args += ["-i", str(random.randint(0, 5))]
    if random.random() < 0.4:
        args += ["--sniff", str(random.choice([0, 1, 2, 5, 100, 1000]))]
    if random.random() < 0.3:
        args += ["--header-align", random.choice(ALIGNS)]
    if random.random() < 0.3:
        args += ["--body-align", random.choice(ALIGNS)]
    return args


def random_csv(delim=","):
    nrows = random.randint(0, 6)
    ncols = random.randint(1, 5)
    rows = []
    for _ in range(nrows):
        row = []
        for _ in range(ncols):
            cell_kind = random.choice(["short", "alpha", "numeric", "cjk", "empty", "with_space", "with_quote"])
            if cell_kind == "short":
                row.append(random.choice(["a", "b", "x", "yy"]))
            elif cell_kind == "alpha":
                row.append("".join(random.choices(string.ascii_letters, k=random.randint(1, 8))))
            elif cell_kind == "numeric":
                row.append(str(random.randint(0, 1000)))
            elif cell_kind == "cjk":
                row.append(random.choice(["你好", "日本", "中文", "안녕"]))
            elif cell_kind == "empty":
                row.append("")
            elif cell_kind == "with_space":
                row.append("hello world")
            elif cell_kind == "with_quote":
                row.append('"q"')
            else:
                row.append("?")
        rows.append(delim.join(row))
    return "\n".join(rows) + ("\n" if rows else "")


def run(binary, stdin, args, timeout=5):
    try:
        p = subprocess.run([binary] + args, input=stdin.encode("utf-8", errors="replace"),
                           capture_output=True, timeout=timeout)
        return (p.returncode, p.stdout, p.stderr)
    except subprocess.TimeoutExpired:
        return (124, b"", b"timeout")


def main():
    seed = int(sys.argv[1]) if len(sys.argv) > 1 else 42
    n = int(sys.argv[2]) if len(sys.argv) > 2 else 100
