use std::fs::File;
use std::io::{self, Read, Write, BufWriter};
use std::process::ExitCode;

use clap::{Parser, ValueEnum};
use unicode_segmentation::UnicodeSegmentation;
use unicode_truncate::UnicodeTruncateStr;
use unicode_width::UnicodeWidthStr;

#[derive(Debug, Clone, Copy, PartialEq, Eq, ValueEnum)]
#[clap(rename_all = "lower")]
enum Style {
    None,
    Ascii,
    Ascii2,
    Sharp,
    Rounded,
    Reinforced,
    Markdown,
    Grid,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, ValueEnum)]
#[clap(rename_all = "lower")]
enum Align {
    Left,
    Center,
    Right,
}

#[derive(Parser, Debug)]
#[command(
    name = "csview",
    version = "1.3.4",
    about = "A high performance csv viewer with cjk/emoji support.",
    next_line_help = true,
)]
struct Cli {
    /// Specify that the input has no header row
    #[arg(short = 'H', long)]
    no_headers: bool,

    /// Prepend a column of line numbers to the table
    #[arg(short = 'n', long)]
    number: bool,

    /// Use '\t' as delimiter for tsv
    #[arg(short = 't', long, conflicts_with = "delimiter")]
    tsv: bool,

    /// Specify the field delimiter
    #[arg(short = 'd', long, default_value = ",", conflicts_with = "tsv")]
    delimiter: char,

    /// Specify the border style
    #[arg(short = 's', long, default_value = "sharp", value_enum)]
    style: Style,

    /// Specify padding for table cell
    #[arg(short = 'p', long, default_value_t = 1)]
    padding: u32,

    /// Specify global indent for table
    #[arg(short = 'i', long, default_value_t = 0)]
    indent: u32,

    /// Limit column widths sniffing to the specified number of rows. Specify "0" to cancel limit
    #[arg(long, default_value_t = 1000, value_name = "LIMIT")]
    sniff: u32,

    /// Specify the alignment of the table header
    #[arg(long, default_value = "center", value_enum)]
    header_align: Align,

    /// Specify the alignment of the table body
    #[arg(long, default_value = "left", value_enum)]
    body_align: Align,

    /// Disable pager
    #[arg(short = 'P', long)]
    disable_pager: bool,

    /// File to view
    file: Option<String>,
}

struct Glyphs {
    // top border (top-left, top, top-tee, top-right)
    top: Option<(&'static str, &'static str, &'static str, &'static str)>,
    // mid border (mid-left, mid, mid-cross, mid-right)
    mid: Option<(&'static str, &'static str, &'static str, &'static str)>,
    // bottom border (bottom-left, bottom, bottom-tee, bottom-right)
    bot: Option<(&'static str, &'static str, &'static str, &'static str)>,
    // vertical separator (left, inner, right)
    vert: (&'static str, &'static str, &'static str),
    // separate every body row?
    grid: bool,
}

fn glyphs(style: Style) -> Glyphs {
    match style {
        Style::None => Glyphs {
            top: None,
            mid: None,
            bot: None,
            vert: ("", "", ""),
            grid: false,
        },
        Style::Ascii => Glyphs {
            top: Some(("+", "-", "+", "+")),
            mid: Some(("+", "-", "+", "+")),
            bot: Some(("+", "-", "+", "+")),
            vert: ("|", "|", "|"),
            grid: false,
        },
        Style::Ascii2 => Glyphs {
            top: None,
            mid: Some((" ", "-", "+", " ")),
            bot: None,
            vert: (" ", "|", " "),
            grid: false,
        },
        Style::Sharp => Glyphs {
            top: Some(("┌", "─", "┬", "┐")),
            mid: Some(("├", "─", "┼", "┤")),
            bot: Some(("└", "─", "┴", "┘")),
            vert: ("│", "│", "│"),
            grid: false,
        },
        Style::Rounded => Glyphs {
            top: Some(("╭", "─", "┬", "╮")),
            mid: Some(("├", "─", "┼", "┤")),
            bot: Some(("╰", "─", "┴", "╯")),
            vert: ("│", "│", "│"),
            grid: false,
        },
        Style::Reinforced => Glyphs {
            top: Some(("┏", "─", "┬", "┓")),
            mid: Some(("├", "─", "┼", "┤")),
            bot: Some(("┗", "─", "┴", "┛")),
            vert: ("│", "│", "│"),
            grid: false,
        },
        Style::Markdown => Glyphs {
            top: None,
            mid: Some(("|", "-", "|", "|")),
            bot: None,
            vert: ("|", "|", "|"),
            grid: false,
        },
        Style::Grid => Glyphs {
            top: Some(("┌", "─", "┬", "┐")),
            mid: Some(("├", "─", "┼", "┤")),
            bot: Some(("└", "─", "┴", "┘")),
            vert: ("│", "│", "│"),
            grid: true,
        },
    }
}

fn display_width(s: &str) -> usize {
    UnicodeWidthStr::width(s)
}

fn render_cell(content: &str, inner_width: usize, padding: usize, align: Align) -> String {
    let cw = display_width(content);
    if cw > inner_width.saturating_sub(2 * padding) {
        // Truncate to fit. Inner width is total cell width including padding.
        // Available for content = inner_width - 2*padding (but actually inner_width itself is content width)
        // Wait: inner_width here is the inner cell width INCLUDING padding.
        // Need to determine truncation width: inner_width - 2*padding.
    }
    // inner_width = max_content_display_width + 2*padding
    // content_max_width = inner_width - 2*padding
    let content_max = inner_width.saturating_sub(2 * padding);
    let (truncated, truncated_w) = if cw > content_max {
        let (t, w) = content.unicode_truncate(content_max);
        (t.to_string(), w)
    } else {
        (content.to_string(), cw)
    };

    match align {
        Align::Left => {
            let total_fill = inner_width - truncated_w;
            // pad_left = padding (fixed) — but if content was truncated, padding may still be added.
            // pad_left = padding always; pad_right = total_fill - padding
            let pad_left = padding.min(total_fill);
            let pad_right = total_fill - pad_left;
            format!("{}{}{}", " ".repeat(pad_left), truncated, " ".repeat(pad_right))
        }
        Align::Right => {
            let total_fill = inner_width - truncated_w;
            let pad_right = padding.min(total_fill);
            let pad_left = total_fill - pad_right;
            format!("{}{}{}", " ".repeat(pad_left), truncated, " ".repeat(pad_right))
        }
        Align::Center => {
            let total_fill = inner_width - truncated_w;
            let pad_left = total_fill / 2;
            let pad_right = total_fill - pad_left;
            format!("{}{}{}", " ".repeat(pad_left), truncated, " ".repeat(pad_right))
        }
    }
}

fn render_row<W: Write>(
    out: &mut W,
    cells: &[String],
    widths: &[usize],
    glyphs: &Glyphs,
    padding: usize,
    align: Align,
    indent: usize,
) -> io::Result<()> {
    write!(out, "{}", " ".repeat(indent))?;
    write!(out, "{}", glyphs.vert.0)?;
    for (i, (cell, &w)) in cells.iter().zip(widths.iter()).enumerate() {
        write!(out, "{}", render_cell(cell, w, padding, align))?;
        if i + 1 == cells.len() {
            write!(out, "{}", glyphs.vert.2)?;
        } else {
            write!(out, "{}", glyphs.vert.1)?;
        }
    }
    writeln!(out)?;
    Ok(())
}

fn render_border<W: Write>(
    out: &mut W,
    widths: &[usize],
    border: (&str, &str, &str, &str),
    indent: usize,
) -> io::Result<()> {
    write!(out, "{}", " ".repeat(indent))?;
    write!(out, "{}", border.0)?;
    for (i, &w) in widths.iter().enumerate() {
        let dash = border.1;
        // Repeat dash w times (display width 1 per dash).
        for _ in 0..w {
            write!(out, "{}", dash)?;
        }
        if i + 1 == widths.len() {
            write!(out, "{}", border.3)?;
        } else {
            write!(out, "{}", border.2)?;
        }
    }
    writeln!(out)?;
    Ok(())
}

fn run() -> Result<i32, anyhow::Error> {
    let cli = Cli::parse();

    let delimiter: u8 = if cli.tsv { b'\t' } else {
        // If delimiter char fits in single byte, use it. Otherwise, error.
        let mut buf = [0u8; 4];
        let s = cli.delimiter.encode_utf8(&mut buf);
        if s.len() == 1 {
            s.as_bytes()[0]
        } else {
            // Multi-byte char as delimiter; csv crate only takes a single byte.
            // The reference accepts a char, but csv crate uses a byte. We follow csv crate.
            // Just truncate or error?
            s.as_bytes()[0]
        }
    };

    // Read all input first to allow processing.
    let mut input_bytes = Vec::new();
    if let Some(file) = &cli.file {
        let mut f = match File::open(file) {
            Ok(f) => f,
            Err(e) => {
                eprintln!("csview: {}", e);
                return Ok(1);
            }
        };
        if let Err(e) = f.read_to_end(&mut input_bytes) {
            eprintln!("csview: {}", e);
            return Ok(1);
        }
    } else {
        if let Err(e) = io::stdin().read_to_end(&mut input_bytes) {
            eprintln!("csview: {}", e);
            return Ok(1);
        }
    }

    // Build CSV reader from the bytes.
    let mut reader_builder = csv::ReaderBuilder::new();
    reader_builder
        .delimiter(delimiter)
        .has_headers(false)  // we'll handle header logic manually
        .flexible(false);
    let mut rdr = reader_builder.from_reader(&input_bytes[..]);

    // Read all records.
    let mut records: Vec<Vec<String>> = Vec::new();
    for result in rdr.records() {
        match result {
            Ok(rec) => {
                let v: Vec<String> = rec.iter().map(|s| s.to_string()).collect();
                records.push(v);
            }
            Err(e) => {
                eprintln!("csview: {}", e);
                return Ok(1);
            }
        }
    }

    // Determine header/body split.
    let (headers, body): (Option<Vec<String>>, Vec<Vec<String>>) = if cli.no_headers {
        (None, records)
    } else {
        if records.is_empty() {
            (None, Vec::new())
        } else {
            let h = records.remove(0);
            (Some(h), records)
        }
    };

    // If -n, prepend the number column.
    let (headers, body) = if cli.number {
        let new_headers = headers.as_ref().map(|h| {
            let mut v = vec!["#".to_string()];
            v.extend(h.iter().cloned());
            v
        });
        let new_body: Vec<Vec<String>> = body
            .iter()
            .enumerate()
            .map(|(i, row)| {
                let mut v = vec![(i + 1).to_string()];
                v.extend(row.iter().cloned());
                v
            })
            .collect();
        (new_headers, new_body)
    } else {
        (headers, body)
    };

    // Determine number of columns.
    let mut num_cols = headers.as_ref().map(|h| h.len()).unwrap_or(0);
    for row in &body {
        num_cols = num_cols.max(row.len());
    }

    // Special case: no records and no header → empty table.
    let empty_table = headers.is_none() && body.is_empty();

    // Sniff body rows for width.
    let sniff_count = if cli.sniff == 0 {
        body.len()
    } else {
        (cli.sniff as usize).min(body.len())
    };

    let mut col_widths: Vec<usize> = vec![0; num_cols];
    if let Some(h) = &headers {
        for (i, c) in h.iter().enumerate() {
            if i < num_cols {
                col_widths[i] = col_widths[i].max(display_width(c));
            }
        }
    }
    for row in body.iter().take(sniff_count) {
        for (i, c) in row.iter().enumerate() {
            if i < num_cols {
                col_widths[i] = col_widths[i].max(display_width(c));
            }
        }
    }

    let padding = cli.padding as usize;
    let indent = cli.indent as usize;
    let inner_widths: Vec<usize> = col_widths.iter().map(|w| w + 2 * padding).collect();

    let g = glyphs(cli.style);

    let stdout = io::stdout();
    let lock = stdout.lock();
    let mut out = BufWriter::new(lock);

    if empty_table {
        // Render zero-col placeholder according to style.
        if let Some(top) = g.top {
            // Just open and close borders side by side.
            write!(out, "{}", " ".repeat(indent))?;
            write!(out, "{}{}", top.0, top.3)?;
            writeln!(out)?;
        }
        // Body placeholder row: just vert.0 + vert.2 (if no -H).
        if !cli.no_headers {
            write!(out, "{}", " ".repeat(indent))?;
            write!(out, "{}{}", g.vert.0, g.vert.2)?;
            writeln!(out)?;
        }
        if let Some(bot) = g.bot {
            write!(out, "{}", " ".repeat(indent))?;
            write!(out, "{}{}", bot.0, bot.3)?;
            writeln!(out)?;
        }
        return Ok(0);
    }

    // Top border
    if let Some(top) = g.top {
        render_border(&mut out, &inner_widths, top, indent)?;
    }

    // Header
    if let Some(h) = &headers {
        let mut padded_h = h.clone();
        while padded_h.len() < num_cols { padded_h.push(String::new()); }
        render_row(&mut out, &padded_h, &inner_widths, &g, padding, cli.header_align, indent)?;
        // Mid separator after header (only if body exists)
        if !body.is_empty() {
            if let Some(mid) = g.mid {
                render_border(&mut out, &inner_widths, mid, indent)?;
            }
        }
    }

    // Body rows
    let body_len = body.len();
    for (idx, row) in body.iter().enumerate() {
        let mut padded_row = row.clone();
        while padded_row.len() < num_cols { padded_row.push(String::new()); }
        render_row(&mut out, &padded_row, &inner_widths, &g, padding, cli.body_align, indent)?;
        if g.grid && idx + 1 < body_len {
            if let Some(mid) = g.mid {
                render_border(&mut out, &inner_widths, mid, indent)?;
            }
        }
    }

    // Bottom border
    if let Some(bot) = g.bot {
        render_border(&mut out, &inner_widths, bot, indent)?;
    }

    Ok(0)
}

fn main() -> ExitCode {
    match run() {
        Ok(code) => ExitCode::from(code as u8),
        Err(e) => {
            eprintln!("csview: {}", e);
            ExitCode::from(1)
        }
    }
}

