165	fn render_cell(content: &str, inner_width: usize, padding: usize, align: Align) -> String {
166	    let cw = display_width(content);
167	    if cw > inner_width.saturating_sub(2 * padding) {
168	        // Truncate to fit. Inner width is total cell width including padding.
169	        // Available for content = inner_width - 2*padding (but actually inner_width itself is content width)
170	        // Wait: inner_width here is the inner cell width INCLUDING padding.
171	        // Need to determine truncation width: inner_width - 2*padding.
172	    }
173	    // inner_width = max_content_display_width + 2*padding
174	    // content_max_width = inner_width - 2*padding
175	    let content_max = inner_width.saturating_sub(2 * padding);
176	    let (truncated, truncated_w) = if cw > content_max {
177	        let (t, w) = content.unicode_truncate(content_max);
178	        (t.to_string(), w)
179	    } else {
180	        (content.to_string(), cw)
181	    };
182	
183	    match align {
184	        Align::Left => {
185	            let total_fill = inner_width - truncated_w;
186	            // pad_left = padding (fixed) — but if content was truncated, padding may still be added.
187	            // pad_left = padding always; pad_right = total_fill - padding
188	            let pad_left = padding.min(total_fill);
189	            let pad_right = total_fill - pad_left;
