193	            let total_fill = inner_width - truncated_w;
194	            let pad_right = padding.min(total_fill);
195	            let pad_left = total_fill - pad_right;
196	            format!("{}{}{}", " ".repeat(pad_left), truncated, " ".repeat(pad_right))
197	        }
198	        Align::Center => {
199	            let total_fill = inner_width - truncated_w;
200	            let pad_left = total_fill / 2;
201	            let pad_right = total_fill - pad_left;
202	            format!("{}{}{}", " ".repeat(pad_left), truncated, " ".repeat(pad_right))
203	        }
204	    }
