#!/usr/bin/env python3
"""Statistical top-up using realistic usage patterns."""
import subprocess
import random
import sys

REF = "/workspace/executable"
MINE = "/work/work/executable"


# Realistic usage profiles
def profile_simple_view():
    """View a small CSV with default settings."""
    return ([], "name,age,city\nAlice,30,NYC\nBob,25,LA\nCarol,28,Chicago\n")

def profile_tsv():
    """View TSV file."""
    return (["-t"], "name\tage\tcity\nAlice\t30\tNYC\nBob\t25\tLA\n")

def profile_no_headers():
    """View without headers."""
    return (["-H"], "1,2,3\n4,5,6\n7,8,9\n")

def profile_with_numbers():
    """Add row numbers."""
    return (["-n"], "task,status\nbuild,ok\ntest,fail\ndeploy,pending\n")

def profile_markdown():
    """Output as markdown."""
    return (["-s", "markdown"], "col1,col2,col3\na,b,c\nd,e,f\n")

def profile_unicode():
    """CJK and emoji."""
    return ([], "国家,人口\n中国,14亿\n日本,1.2亿\n美国,3.3亿\n")

def profile_pipe_delim():
    """Pipe-delimited."""
    return (["-d", "|"], "id|name|email\n1|Alice|a@example.com\n2|Bob|b@example.com\n")

def profile_grid_style():
    """Grid border style."""
    return (["-s", "grid", "-p", "2"], "a,b\n1,2\n3,4\n")

def profile_indented():
    """With indent."""
    return (["-i", "4", "-s", "rounded"], "key,value\nfoo,bar\n")

def profile_truncated():
    """Sniff small for truncation."""
    return (["--sniff", "1"], "col1,col2\na,b\nLONGER_DATA,EVEN_LONGER\n")


PROFILES = [
    profile_simple_view, profile_tsv, profile_no_headers, profile_with_numbers,
    profile_markdown, profile_unicode, profile_pipe_delim, profile_grid_style,
    profile_indented, profile_truncated,
]


def run(binary, stdin, args, timeout=5):
    p = subprocess.run([binary] + args, input=stdin.encode("utf-8"),
                       capture_output=True, timeout=timeout)
    return (p.returncode, p.stdout, p.stderr)


def main():
    random.seed(42)
    # Sample 10 random profiles
    sampled = random.sample(PROFILES, 10) if len(PROFILES) == 10 else random.choices(PROFILES, k=10)
    pass_ct = 0
    fail_ct = 0
    for i, p in enumerate(sampled):
        args, stdin = p()
        a, b, c = run(REF, stdin, args)
        d, e, f = run(MINE, stdin, args)
        ok = (a, b, c) == (d, e, f)
        status = "PASS" if ok else "FAIL"
        print(f"{status} #{i+1}: {p.__name__} args={args}")
        if ok:
            pass_ct += 1
        else:
            fail_ct += 1
            print(f"  ref: exit={a} stdout={b!r} stderr={c!r}")
            print(f"  mine: exit={d} stdout={e!r} stderr={f!r}")
    print(f"\nTotal: PASS={pass_ct}/10")


if __name__ == "__main__":
    main()
